import React from "react";
import { useNavigate } from "react-router-dom";

function LandingPage() {
  const navigate = useNavigate();

  return (
    <div style={styles.container}>

      {/* Card */}
      <div style={styles.card}>

        {/* Logo Section */}
        <div style={styles.logoContainer}>
          <img
            src="https://cdn-icons-png.flaticon.com/512/2966/2966485.png"
            alt="DocBook Logo"
            style={styles.logoImg}
          />
          <h1 style={styles.logoText}>DocBook</h1>
        </div>

        {/* Content */}
        <h2 style={styles.title}>Welcome to DocBook</h2>

        <p style={styles.subtitle}>
          Book doctor appointments easily and manage your healthcare in one place.
        </p>

        {/* Buttons */}
        <div style={styles.buttons}>
          <button
            style={styles.loginBtn}
            onClick={() => navigate("/login")}
          >
            Login
          </button>

          <button
            style={styles.registerBtn}
            onClick={() => navigate("/register")}
          >
            Register
          </button>
        </div>

      </div>

    </div>
  );
}

export default LandingPage;

const styles = {
  container: {
    height: "100vh",
    background: "linear-gradient(135deg, #2563EB, #1E40AF)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "Arial, sans-serif",
  },

  card: {
    backgroundColor: "white",
    padding: "40px",
    borderRadius: "16px",
    textAlign: "center",
    width: "380px",
    boxShadow: "0 10px 30px rgba(0,0,0,0.2)",
  },

  logoContainer: {
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    gap: "10px",
    marginBottom: "15px",
  },

  logoImg: {
    width: "40px",
    height: "40px",
  },

  logoText: {
    color: "#2563EB",
    margin: 0,
  },

  title: {
    fontSize: "24px",
    marginBottom: "10px",
    color: "#333",
  },

  subtitle: {
    fontSize: "14px",
    color: "#666",
    marginBottom: "25px",
  },

  buttons: {
    display: "flex",
    gap: "10px",
    justifyContent: "center",
  },

  loginBtn: {
    padding: "10px 18px",
    borderRadius: "6px",
    border: "1px solid #2563EB",
    backgroundColor: "white",
    color: "#2563EB",
    cursor: "pointer",
    fontWeight: "500",
  },

  registerBtn: {
    padding: "10px 18px",
    borderRadius: "6px",
    border: "none",
    backgroundColor: "#10B981",
    color: "white",
    cursor: "pointer",
    fontWeight: "500",
  },
};
